prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?model
  ?modelName
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (COUNT(DISTINCT ?taskNoOp) AS ?tasksNotExecutableDuringOperationCount)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "3c08e52742754da6a4065fc5787131dc" ;
         bbo:name ?modelName .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?model .

  OPTIONAL {
    ?task bboExt:loopType ?loopType .
  }

  FILTER(NOT EXISTS {
    ?task bboExt:loopType ?loopType .
    FILTER(?loopType IN ("None"))
  })

  # Any task failing the above constraint will be counted as not executable during operation.
  BIND(IF( EXISTS {
    ?task bboExt:loopType ?loopType2 .
    FILTER(?loopType2 IN ("None"))
  }, false, true) AS ?isNotExecutableDuringOperation)

  BIND(
    IF(?isNotExecutableDuringOperation = true, ?task, UNDEF)
    AS ?taskNoOp
  )
}
GROUP BY ?model ?modelName

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?model
  ?modelName
  ?originalId
  ?normalizedId
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (SUM(?notExecFlag) AS ?tasksNotExecutableDuringOperationCount)
WHERE {
  {
    ?model a bboExt:Model ;
           tai:normalizedId ?idVal .
    FILTER(CONTAINS(LCASE(STR(?idVal)), LCASE("3c08e52742754da6a4065fc5787131dc")))
  }
  UNION
  {
    ?model a bboExt:Model ;
           tai:originalId ?idVal .
    FILTER(CONTAINS(LCASE(STR(?idVal)), LCASE("3c08e52742754da6a4065fc5787131dc")))
  }
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?model .

  OPTIONAL { ?task bboExt:loopType ?loopType . }

  BIND(
    IF(
      EXISTS { ?task bboExt:loopType ?loopTypeX . FILTER(?loopTypeX = "None") },
      0,
      1
    )
    AS ?notExecFlag
  )
}
GROUP BY ?model ?modelName ?originalId ?normalizedId
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?model
  ?modelName
  ?normalizedId
  ?originalId
  (COUNT(DISTINCT ?task) AS ?taskCount)
WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }
  OPTIONAL { ?model tai:originalId ?originalId . }

  FILTER(
    (BOUND(?normalizedId) && CONTAINS(LCASE(STR(?normalizedId)), LCASE("3c08e527"))) ||
    (BOUND(?originalId) && CONTAINS(LCASE(STR(?originalId)), LCASE("3c08e527"))) ||
    (BOUND(?modelName) && CONTAINS(LCASE(STR(?modelName)), LCASE("3c08e527")))
  )

  OPTIONAL {
    ?task a bboExt:ChoreographyTask ;
          tai:belongsTo ?choreo .
    ?choreo tai:belongsTo ?model .
  }
}
GROUP BY ?model ?modelName ?normalizedId ?originalId
ORDER BY DESC(?taskCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?type (COUNT(*) AS ?cnt) WHERE {
  {
    SELECT ?model WHERE {
      ?model a bboExt:Model ;
             tai:originalId "3c08e52742754da6a4065fc5787131dc" .
    } LIMIT 1
  }
  ?elem tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?model .
  ?elem a ?type .
}
GROUP BY ?type
ORDER BY DESC(?cnt)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?node
  ?nodeType
  (COALESCE(?nodeName, "") AS ?nodeName)
  ?loopType
WHERE {
  {
    SELECT ?model WHERE {
      ?model a bboExt:Model ;
             tai:originalId "3c08e52742754da6a4065fc5787131dc" .
    }
  }
  ?node tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?model .

  OPTIONAL { ?node a ?nodeType . }
  OPTIONAL { ?node bbo:name ?nodeName . }
  OPTIONAL { ?node bboExt:loopType ?loopType . }

  FILTER(
    EXISTS { ?node bboExt:initiatingParticipantRef ?pRef . } ||
    EXISTS { ?node bboExt:loopType ?lt . }
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?node
  ?nodeType
  (COALESCE(?nameVal, "") AS ?nodeLabel)
  ?loopType
WHERE {
  {
    SELECT ?model WHERE {
      ?model a bboExt:Model ;
             tai:originalId "3c08e52742754da6a4065fc5787131dc" .
    }
  }

  ?node tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?model .

  ?node a ?nodeType .
  OPTIONAL { ?node bbo:name ?nameVal . }
  OPTIONAL { ?node bboExt:loopType ?loopType . }

  FILTER(
    EXISTS { ?node bboExt:initiatingParticipantRef ?pRef } ||
    EXISTS { ?node bboExt:loopType ?lt }
  )
}
LIMIT 25
